# Fields that only admins should be able to modify
ADMIN_ONLY_FIELDS = {"role", "is_admin", "credits", "subscription_tier"}

# Fields that regular users can modify on their own profile
USER_EDITABLE_FIELDS = {"username", "email", "bio"}

# Valid subscription tiers
VALID_SUBSCRIPTION_TIERS = {"free", "basic", "premium", "enterprise"}

# Valid roles
VALID_ROLES = {"user", "moderator", "admin"}


class UpdateUserProfile(Mutation):
    class Arguments:
        user_id = String(required=True, description="ID of the user to update")
        username = String(description="New username")
        email = String(description="New email address")
        bio = String(description="New bio")
        role = String(description="New role (admin only)")
        is_admin = Boolean(description="Admin status (admin only)")
        credits = Int(description="Credit balance (admin only)")
        subscription_tier = String(description="Subscription tier (admin only)")

    user = Field(UserType)
    success = Boolean(required=True)
    message = String(required=True)

    @staticmethod
    def mutate(root, info, user_id, **kwargs):
        # Get authenticated user from context
        authenticated_user = info.context.get("current_user") if hasattr(info.context, "get") else getattr(info.context, "current_user", None)

        if not authenticated_user:
            return UpdateUserProfile(
                user=None,
                success=False,
                message="Authentication required. No authenticated user found in context.",
            )

        auth_user_id = authenticated_user.get("id")
        auth_is_admin = authenticated_user.get("is_admin", False)

        # Check if target user exists
        if user_id not in USERS_DB:
            return UpdateUserProfile(
                user=None,
                success=False,
                message=f"User with ID '{user_id}' not found.",
            )

        # Determine which fields are being updated (non-None values)
        fields_to_update = {k: v for k, v in kwargs.items() if v is not None}

        if not fields_to_update:
            return UpdateUserProfile(
                user=None,
                success=False,
                message="No fields provided for update.",
            )

        is_self_update = auth_user_id == user_id

        # Authorization checks
        if not auth_is_admin:
            # Non-admin users can only update their own profile
            if not is_self_update:
                return UpdateUserProfile(
                    user=None,
                    success=False,
                    message="Permission denied. You can only update your own profile.",
                )

            # Check if non-admin is trying to update admin-only fields
            attempted_admin_fields = set(fields_to_update.keys()) & ADMIN_ONLY_FIELDS
            if attempted_admin_fields:
                return UpdateUserProfile(
                    user=None,
                    success=False,
                    message=f"Permission denied. Only admins can modify: {', '.join(sorted(attempted_admin_fields))}.",
                )

        # Validate individual fields
        if "username" in fields_to_update:
            username = fields_to_update["username"]
            if not username or not username.strip():
                return UpdateUserProfile(
                    user=None,
                    success=False,
                    message="Username cannot be empty.",
                )
            if len(username) < 3:
                return UpdateUserProfile(
                    user=None,
                    success=False,
                    message="Username must be at least 3 characters long.",
                )
            if len(username) > 50:
                return UpdateUserProfile(
                    user=None,
                    success=False,
                    message="Username must not exceed 50 characters.",
                )
            # Check uniqueness
            for uid, udata in USERS_DB.items():
                if uid != user_id and udata["username"].lower() == username.lower():
                    return UpdateUserProfile(
                        user=None,
                        success=False,
                        message=f"Username '{username}' is already taken.",
                    )

        if "email" in fields_to_update:
            email = fields_to_update["email"]
            if not email or "@" not in email or "." not in email.split("@")[-1]:
                return UpdateUserProfile(
                    user=None,
                    success=False,
                    message="Invalid email address format.",
                )
            # Check uniqueness
            for uid, udata in USERS_DB.items():
                if uid != user_id and udata["email"].lower() == email.lower():
                    return UpdateUserProfile(
                        user=None,
                        success=False,
                        message=f"Email '{email}' is already in use.",
                    )

        if "bio" in fields_to_update:
            bio = fields_to_update["bio"]
            if len(bio) > 500:
                return UpdateUserProfile(
                    user=None,
                    success=False,
                    message="Bio must not exceed 500 characters.",
                )

        if "role" in fields_to_update:
            role = fields_to_update["role"]
            if role not in VALID_ROLES:
                return UpdateUserProfile(
                    user=None,
                    success=False,
                    message=f"Invalid role '{role}'. Valid roles are: {', '.join(sorted(VALID_ROLES))}.",
                )

        if "credits" in fields_to_update:
            credits = fields_to_update["credits"]
            if credits < 0:
                return UpdateUserProfile(
                    user=None,
                    success=False,
                    message="Credits cannot be negative.",
                )

        if "subscription_tier" in fields_to_update:
            tier = fields_to_update["subscription_tier"]
            if tier not in VALID_SUBSCRIPTION_TIERS:
                return UpdateUserProfile(
                    user=None,
                    success=False,
                    message=f"Invalid subscription tier '{tier}'. Valid tiers are: {', '.join(sorted(VALID_SUBSCRIPTION_TIERS))}.",
                )

        # Prevent admin from removing their own admin status (safety check)
        if is_self_update and auth_is_admin:
            if "is_admin" in fields_to_update and fields_to_update["is_admin"] is False:
                return UpdateUserProfile(
                    user=None,
                    success=False,
                    message="Admins cannot remove their own admin status.",
                )
            if "role" in fields_to_update and fields_to_update["role"] != "admin":
                return UpdateUserProfile(
                    user=None,
                    success=False,
                    message="Admins cannot demote their own role.",
                )

        # Apply updates
        target_user = USERS_DB[user_id]
        updated_fields = []
        for field_name, field_value in fields_to_update.items():
            old_value = target_user.get(field_name)
            if old_value != field_value:
                target_user[field_name] = field_value
                updated_fields.append(field_name)

        if not updated_fields:
            return UpdateUserProfile(
                user=UserType(**target_user),
                success=True,
                message="No changes detected. Profile is already up to date.",
            )

        updated_user = UserType(**target_user)

        return UpdateUserProfile(
            user=updated_user,
            success=True,
            message=f"Successfully updated fields: {', '.join(sorted(updated_fields))}.",
        )


class Query(ObjectType):
    user = Field(UserType, user_id=String(required=True))
    me = Field(UserType)
    users = graphene.List(UserType)

    def resolve_user(root, info, user_id):
        user_data = USERS_DB.get(user_id)
        if user_data:
            return UserType(**user_data)
        return None

    def resolve_me(root, info):
        authenticated_user = info.context.get("current_user") if hasattr(info.context, "get") else getattr(info.context, "current_user", None)
        if authenticated_user:
            user_data = USERS_DB.get(authenticated_user["id"])
            if user_data:
                return UserType(**user_data)
        return None

    def resolve_users(root, info):
        authenticated_user = info.context.get("current_user") if hasattr(info.context, "get") else getattr(info.context, "current_user", None)
        if not authenticated_user or not authenticated_user.get("is_admin", False):
            return []
        return [UserType(**data) for data in USERS_DB.values()]


class MutationType(ObjectType):
    update_user_profile = UpdateUserProfile.Field()


schema = Schema(query=Query, mutation=MutationType)


def execute_query(query, variables=None, current_user=None):
    """Helper function to execute a GraphQL query with context."""
    context = {"current_user": current_user}
    result = schema.execute(query, variables=variables, context=context)
    response = {}
    if result.data:
        response["data"] = result.data
    if result.errors:
        response["errors"] = [str(e) for e in result.errors]
    return response


